<html lang="ar" dir="rtl">
<head>
    <meta charset="UTF-8">
    <title>مولد الجيم مود الكامل</title>
    <style>
        body { font-family: Arial; background:#1a1a2e; color:#fff; padding:20px; }
        .gm-box { background:#16213e; padding:20px; border-radius:10px; }
        input { padding:10px; margin:5px 0; background:#000; color:#fff; border:1px solid #0f0; }
        button { padding:10px 15px; background:#00aa00; color:#fff; border:none; cursor:pointer; }
    </style>
</head>
<body>
    <a href="index.php">العودة للوحة التحكم</a>
    <div class="gm-box">
        <h2>مولد الجيم مود الكامل</h2>
        <form method="POST">
            <input type="text" name="gm_name" placeholder="اسم الجيم مود" required>
            <label><input type="checkbox" name="use_db"> استخدام قاعدة البيانات</label>
            <input type="text" name="fs_list[]" placeholder="فلاتر إضافية (مثلاً: sscanf)">
            <button type="submit">إنشاء جيم مود كامل</button>
        </form>
    </div>
</body>
</html>